'use strict';
const Utils = use('Utils');
const Request = use('Request');
const DBService = use('DBService');
const serverUrl = 'http://demosign.easyca.vn:8080/api';
const username = 'demo_easysign';
const password = 'demo_easysign';
const serial = '540110beffa622f3ca84bd2f93f0122c';
const pin = '12345678';
const serviceUrl = 'http://localhost:56666/api';
const axios = require('axios');
const fs = require('fs');
const EINVOICE_ESIGN_XML = 'http://csharp-api.webcashvietnam.com/wseinvoice/BSService.asmx/SignXml';

const signatureImage =
  '';
const pdfContent =
  '';
const pdfPath = '/opt/easysign/sample.pdf';
// pixel
const positionX = 400;
const positionY = 200;
const imageWidth = 200;
const imageHeight = 200;
const numPage = 1;
class HSMController {
  async loginToServer() {
    let body = {
      username: username,
      password: password,
      rememberMe: false,
    };
    let token;
    await axios
      .post(serverUrl + '/authenticate', body)
      .then(res => {
        token = res.data.id_token;
      })
      .catch(err => {
        console.log(err);
      });
    return token;
  }

  async getCert(token) {
    let certData = '';
    await axios
      .get(serverUrl + `/certificate/get?serial=${serial}&pin=${pin}`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      })
      .then(res => {
        certData = res.data.data;
      })
      .catch(error => {
        console.log(error);
      });
    return certData;
  }

  async createPdfHash(signatureImage, certData, pdfContent, positionX, positionY, imageWidth, imageHeight, pageNum, hashAlgorithm) {
    var jsondata = {
      signatureImage: signatureImage,
      content: pdfContent,
      chain: [certData],
      visibleX: this.standardizedData(positionX),
      visibleY: this.standardizedData(positionY),
      visibleWidth: this.standardizedData(imageWidth),
      visibleHeight: this.standardizedData(imageHeight),
      pageNum: pageNum,
      reason: 'Ko ly do',
      signerLabel: 'Nguoi ky',
      signDateLabel: 'Ngay ky',
      hashAlgorithm: hashAlgorithm,
    };
    var hashContent = {};
    await axios
      .post(serviceUrl + '/createHash', jsondata)
      .then(res => {
        hashContent = {
          content: res.data.data.content,
          key: res.data.data.key,
        };
      })
      .catch(error => {
        console.log(error);
      });
    return hashContent;
  }

  async signHash(token, hash, hashAlgorithm) {
    const randomNum = Math.random();
    let jsonData = {
      elements: [
        {
          content: hash,
          key: randomNum,
          signDate: '',
          signer: '',
        },
      ],
      optional: {
        hashAlgorithm: hashAlgorithm,
        returnInputData: true,
        signAlgorithm: 'RSA',
        otpCode: null,
      },
      tokenInfo: {
        pin: pin,
        serial: serial,
      },
    };
    let base64Signature = '';
    await axios
      .post(serverUrl + `/sign/hashWithoutInfo`, jsonData, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      })
      .then(res => {
        base64Signature = res.data.data.signResult[0].base64Signature;
      })
      .catch(error => {
        console.log(error);
      });
    return base64Signature;
  }

  async wrapSignature(signature, key) {
    let jsonData = {
      signature: signature,
      key: key,
    };
    let signedContent = '';
    await axios
      .post(serviceUrl + `/wrapContent`, jsonData)
      .then(res => {
        signedContent = res.data;
      })
      .catch(error => {
        console.log(error);
      });
    return signedContent;
  }

  async signPdf({request, response, auth}) {
    try {
      var hashAlgorithm = 'SHA256';
      var token = await this.loginToServer();
      var certData = await this.getCert(token);
      var hash = await this.createPdfHash(
        signatureImage,
        certData,
        pdfContent,
        positionX,
        positionY,
        imageWidth,
        imageHeight,
        numPage,
        hashAlgorithm,
      );
      var signature = await this.signHash(token, hash.content, hashAlgorithm);
      var signedContent = await this.wrapSignature(signature, hash.key);
      // base64 of signed pdf
      //console.log(signedContent);
      return response.status(200).json(Utils.responseByRule({success: true, message: 'success.', data: signedContent}));
    } catch (err) {
      return response.status(400).json(Utils.responseByRule({success: false, message: 'Faile sign.'}));
    }
  }

  standardizedData(value) {
    // convert pixel to inch
    return (value / 96) * 72;
  }

  async HSMGeneralQRCode({request, response, auth}) {
    try {
      var p_language = request.header('accept-language', 'ENG');
      var p_crt_by = '';
      const user = await auth.getUser();
      if (user) {
        p_crt_by = user.USER_ID;
      }

      const {serial, pin} = request.all();

      const body = {
        username: '1201496252', //  HSM_Username,
        password: '1201496252', //
        rememberMe: false,
      };

      const token = await Request.post(`https://sign.easyca.vn/api` + '/authenticate', body);

      //console.log("token  ", token)
      if (token.data.id_token) {
        const certData = await Request.get(`https://sign.easyca.vn/api` + `/certificate/getQRCodeOTP?serial=${serial}&pin=${pin}`, {
          headers: {
            Authorization: `Bearer ${token.data.id_token}`,
          },
        });
        console.log('certData  ', certData.data.data);
        return {
          msg: 'General QR Code sussces !!',
          data: certData.data.data,
        };
      } else {
        console.error('Failed to get api token');
        return {
          msg: 'Failed to get api token',
          data: '',
        };
      }
    } catch (err) {
      console.log('err', err);
      return null;
    }
  }
}

module.exports = HSMController;
